    85→// CompactSignature compacts all cases for a specific error signature
    86→func (cj *CompactionJob) CompactSignature(ctx context.Context, lang, signature string) (*DeduplicationStats, error) {
    87→	stats := &DeduplicationStats{}
    88→	startTime := time.Now()
    89→	defer func() {
    90→		stats.CompactionDuration = time.Since(startTime)
    91→	}()
    92→
    93→	// Acquire lock for this signature
    94→	lockKey := BuildSignatureLockKey(lang, signature)
    95→	lockConfig := DefaultLockConfig()
    96→	lockConfig.DefaultTTL = cj.config.CompactionTimeout
    97→
    98→	err := cj.lockMgr.TryWithLockRetry(ctx, lockKey, lockConfig, func() error {
    99→		return cj.compactSignatureLocked(ctx, lang, signature, stats)
   100→	})
   101→
   102→	if err != nil {
   103→		stats.Errors = append(stats.Errors, fmt.Sprintf("compaction failed for %s/%s: %v", lang, signature, err))
   104→	}
   105→
   106→	return stats, err
   107→}
