   109→// compactSignatureLocked performs compaction under lock
   110→func (cj *CompactionJob) compactSignatureLocked(ctx context.Context, lang, signature string, stats *DeduplicationStats) error {
   111→	stats.SignaturesAnalyzed++
   112→
   113→	// Read all cases for this signature
   114→	cases, err := cj.storage.ReadCases(ctx, lang, signature)
   115→	if err != nil {
   116→		return fmt.Errorf("failed to read cases: %w", err)
   117→	}
   118→
   119→	if len(cases) < cj.config.MinCasesForCompaction {
   120→		return nil // Not enough cases to warrant compaction
   121→	}
   122→
   123→	stats.CasesAnalyzed = len(cases)
   124→
   125→	// Apply retention policy - remove old cases
   126→	retainedCases := cj.applyRetentionPolicy(cases)
   127→	if len(retainedCases) < len(cases) {
   128→		stats.CasesDeleted = len(cases) - len(retainedCases)
   129→		cases = retainedCases
   130→	}
   131→
   132→	// Find duplicate/similar cases for merging
   133→	duplicateGroups := cj.findDuplicateCases(cases)
   134→
   135→	// Merge duplicate cases
   136→	mergedCases, merged := cj.mergeDuplicateCases(cases, duplicateGroups)
   137→	stats.CasesMerged = merged
   138→
   139→	// If we made changes, rewrite the cases
   140→	if len(mergedCases) != len(cases) || merged > 0 {
   141→		if !cj.config.DryRun {
   142→			err = cj.rewriteCases(ctx, lang, signature, mergedCases)
   143→			if err != nil {
   144→				return fmt.Errorf("failed to rewrite cases: %w", err)
   145→			}
   146→
   147→			// Recompute summary after compaction
   148→			err = cj.summaryComputer.ComputeAndUpdateSummary(ctx, lang, signature)
   149→			if err != nil {
   150→				// Don't fail compaction if summary update fails
   151→				stats.Errors = append(stats.Errors, fmt.Sprintf("summary update failed: %v", err))
   152→			}
   153→		}
   154→	}
   155→
   156→	return nil
   157→}
