   159→// applyRetentionPolicy removes cases that are too old
   160→func (cj *CompactionJob) applyRetentionPolicy(cases []*CaseRecord) []*CaseRecord {
   161→	cutoffTime := time.Now().Add(-cj.config.MaxCaseAge)
   162→	var retained []*CaseRecord
   163→
   164→	// Sort by timestamp to keep the most recent cases
   165→	sort.Slice(cases, func(i, j int) bool {
   166→		return cases[i].Timestamp.After(cases[j].Timestamp)
   167→	})
   168→
   169→	kept := 0
   170→	for _, caseRecord := range cases {
   171→		// Always keep minimum number of cases
   172→		if kept < cj.config.MinCasesToRetain {
   173→			retained = append(retained, caseRecord)
   174→			kept++
   175→			continue
   176→		}
   177→
   178→		// Keep cases within retention period
   179→		if caseRecord.Timestamp.After(cutoffTime) {
   180→			retained = append(retained, caseRecord)
   181→			kept++
   182→		}
   183→	}
   184→
   185→	return retained
   186→}
