   188→// findDuplicateCases identifies groups of similar cases that can be merged
   189→func (cj *CompactionJob) findDuplicateCases(cases []*CaseRecord) [][]int {
   190→	var duplicateGroups [][]int
   191→	processed := make(map[int]bool)
   192→
   193→	for i, case1 := range cases {
   194→		if processed[i] {
   195→			continue
   196→		}
   197→
   198→		group := []int{i}
   199→		processed[i] = true
   200→
   201→		// Find similar cases
   202→		for j := i + 1; j < len(cases); j++ {
   203→			if processed[j] {
   204→				continue
   205→			}
   206→
   207→			case2 := cases[j]
   208→			if cj.areCasesSimilar(case1, case2) {
   209→				group = append(group, j)
   210→				processed[j] = true
   211→			}
   212→		}
   213→
   214→		// Only create groups with multiple cases
   215→		if len(group) > 1 {
   216→			duplicateGroups = append(duplicateGroups, group)
   217→		}
   218→	}
   219→
   220→	return duplicateGroups
   221→}
