   223→// areCasesSimilar determines if two cases are similar enough to merge
   224→func (cj *CompactionJob) areCasesSimilar(case1, case2 *CaseRecord) bool {
   225→	// Must be same language and signature
   226→	if case1.Language != case2.Language || case1.Signature != case2.Signature {
   227→		return false
   228→	}
   229→
   230→	// Must have same attempt type
   231→	if case1.Attempt == nil || case2.Attempt == nil {
   232→		return case1.Attempt == case2.Attempt
   233→	}
   234→
   235→	if case1.Attempt.Type != case2.Attempt.Type {
   236→		return false
   237→	}
   238→
   239→	// For recipe attempts, must use same recipe
   240→	if case1.Attempt.Type == "orw_recipe" {
   241→		return case1.Attempt.Recipe == case2.Attempt.Recipe
   242→	}
   243→
   244→	// For patch attempts, check patch similarity
   245→	if case1.Attempt.Type == "llm_patch" {
   246→		if case1.Attempt.PatchFingerprint == case2.Attempt.PatchFingerprint {
   247→			return true // Same patch
   248→		}
   249→
   250→		// Check if patches are similar
   251→		if case1.Attempt.PatchContent != "" && case2.Attempt.PatchContent != "" {
   252→			similarity := cj.sigGenerator.ComputePatchSimilarity(
   253→				[]byte(case1.Attempt.PatchContent),
   254→				[]byte(case2.Attempt.PatchContent),
   255→			)
   256→			return similarity >= cj.config.SimilarityThresholdForMerge
   257→		}
   258→	}
   259→
   260→	// Check context similarity
   261→	return cj.areContextsSimilar(case1.Context, case2.Context)
   262→}
