   264→// areContextsSimilar checks if two case contexts are similar
   265→func (cj *CompactionJob) areContextsSimilar(ctx1, ctx2 *CaseContext) bool {
   266→	if ctx1 == nil || ctx2 == nil {
   267→		return ctx1 == ctx2
   268→	}
   269→
   270→	// Same language and basic context
   271→	if ctx1.Language != ctx2.Language || ctx1.Lane != ctx2.Lane {
   272→		return false
   273→	}
   274→
   275→	// Same repository (allows for similar builds)
   276→	if ctx1.RepoURL != ctx2.RepoURL {
   277→		return false
   278→	}
   279→
   280→	// Similar build command and compiler version
   281→	if ctx1.BuildCommand != ctx2.BuildCommand {
   282→		return false
   283→	}
   284→
   285→	if ctx1.CompilerVersion != ctx2.CompilerVersion {
   286→		return false
   287→	}
   288→
   289→	return true
   290→}
