   292→// mergeDuplicateCases merges groups of duplicate cases
   293→func (cj *CompactionJob) mergeDuplicateCases(cases []*CaseRecord, groups [][]int) ([]*CaseRecord, int) {
   294→	if len(groups) == 0 {
   295→		return cases, 0
   296→	}
   297→
   298→	result := make([]*CaseRecord, 0, len(cases))
   299→	toSkip := make(map[int]bool)
   300→	totalMerged := 0
   301→
   302→	// Process each group
   303→	for _, group := range groups {
   304→		if len(group) <= 1 {
   305→			continue
   306→		}
   307→
   308→		// Merge group into the most recent case
   309→		mergedCase := cj.mergeCaseGroup(cases, group)
   310→		result = append(result, mergedCase)
   311→
   312→		// Mark other cases in group to skip
   313→		for i := 1; i < len(group); i++ {
   314→			toSkip[group[i]] = true
   315→		}
   316→
   317→		totalMerged += len(group) - 1
   318→	}
   319→
   320→	// Add non-duplicate cases
   321→	for i, caseRecord := range cases {
   322→		if !toSkip[i] {
   323→			result = append(result, caseRecord)
   324→		}
   325→	}
   326→
   327→	return result, totalMerged
   328→}
