   330→// mergeCaseGroup merges a group of similar cases into one representative case
   331→func (cj *CompactionJob) mergeCaseGroup(cases []*CaseRecord, groupIndices []int) *CaseRecord {
   332→	// Use the most recent case as the base
   333→	sort.Slice(groupIndices, func(i, j int) bool {
   334→		return cases[groupIndices[i]].Timestamp.After(cases[groupIndices[j]].Timestamp)
   335→	})
   336→
   337→	baseCase := *cases[groupIndices[0]] // Copy the base case
   338→
   339→	// Aggregate statistics from all cases in the group
   340→	// For now, we'll keep the most recent case and add a note about merging
   341→	// In a more sophisticated implementation, we could aggregate outcomes
   342→
   343→	if baseCase.Context == nil {
   344→		baseCase.Context = &CaseContext{}
   345→	}
   346→
   347→	if baseCase.Context.Metadata == nil {
   348→		baseCase.Context.Metadata = make(map[string]string)
   349→	}
   350→
   351→	// Add metadata about the merge
   352→	baseCase.Context.Metadata["merged_cases"] = fmt.Sprintf("%d", len(groupIndices))
   353→	baseCase.Context.Metadata["merge_timestamp"] = time.Now().Format(time.RFC3339)
   354→
   355→	// Update run ID to indicate this is a merged case
   356→	baseCase.RunID = baseCase.RunID + "_merged_" + fmt.Sprintf("%d", time.Now().Unix())
   357→
   358→	return &baseCase
   359→}
