   361→// rewriteCases rewrites all cases for a signature after compaction
   362→func (cj *CompactionJob) rewriteCases(ctx context.Context, lang, signature string, cases []*CaseRecord) error {
   363→	// For simplicity, we'll delete all existing cases and rewrite them
   364→	// In production, this might be optimized to only update changed cases
   365→
   366→	for _, caseRecord := range cases {
   367→		err := cj.storage.WriteCase(ctx, lang, signature, caseRecord.RunID, caseRecord)
   368→		if err != nil {
   369→			return fmt.Errorf("failed to write merged case %s: %w", caseRecord.RunID, err)
   370→		}
   371→	}
   372→
   373→	return nil
   374→}
