   376→// CompactAllSignatures runs compaction across all signatures in the KB
   377→func (cj *CompactionJob) CompactAllSignatures(ctx context.Context) (*DeduplicationStats, error) {
   378→	totalStats := &DeduplicationStats{}
   379→	startTime := time.Now()
   380→	defer func() {
   381→		totalStats.CompactionDuration = time.Since(startTime)
   382→	}()
   383→
   384→	// Get KB snapshot to find all signatures
   385→	snapshot, err := cj.storage.ReadSnapshot(ctx)
   386→	if err != nil {
   387→		return totalStats, fmt.Errorf("failed to read KB snapshot: %w", err)
   388→	}
   389→
   390→	// Compact each language's signatures
   391→	for lang := range snapshot.Languages {
   392→		langStats, err := cj.compactLanguage(ctx, lang)
   393→		if err != nil {
   394→			totalStats.Errors = append(totalStats.Errors, fmt.Sprintf("language %s: %v", lang, err))
   395→		}
   396→
   397→		// Aggregate statistics
   398→		totalStats.SignaturesAnalyzed += langStats.SignaturesAnalyzed
   399→		totalStats.CasesAnalyzed += langStats.CasesAnalyzed
   400→		totalStats.CasesMerged += langStats.CasesMerged
   401→		totalStats.CasesDeleted += langStats.CasesDeleted
   402→		totalStats.PatchesDeduplicated += langStats.PatchesDeduplicated
   403→		totalStats.StorageSaved += langStats.StorageSaved
   404→		totalStats.Errors = append(totalStats.Errors, langStats.Errors...)
   405→	}
   406→
   407→	return totalStats, nil
   408→}
