   445→// DeduplicatePatches finds and merges similar patches
   446→func (pd *PatchDeduplicator) DeduplicatePatches(ctx context.Context, fingerprints []string) (*DeduplicationStats, error) {
   447→	stats := &DeduplicationStats{}
   448→
   449→	if len(fingerprints) < 2 {
   450→		return stats, nil
   451→	}
   452→
   453→	// Load all patches
   454→	patches := make(map[string][]byte)
   455→	for _, fingerprint := range fingerprints {
   456→		patch, err := pd.storage.GetPatch(ctx, fingerprint)
   457→		if err != nil {
   458→			continue // Skip missing patches
   459→		}
   460→		patches[fingerprint] = patch
   461→	}
   462→
   463→	// Find similar patches
   464→	duplicateGroups := pd.findSimilarPatches(patches)
   465→
   466→	// For each group, keep the shortest patch and redirect others
   467→	for _, group := range duplicateGroups {
   468→		if len(group) <= 1 {
   469→			continue
   470→		}
   471→
   472→		// Find the canonical patch (shortest one as it's likely most concise)
   473→		canonical := group[0]
   474→		for _, fingerprint := range group[1:] {
   475→			if len(patches[fingerprint]) < len(patches[canonical]) {
   476→				canonical = fingerprint
   477→			}
   478→		}
   479→
   480→		// In a full implementation, we would update all references to point to the canonical patch
   481→		// For now, we just count the deduplication
   482→		stats.PatchesDeduplicated += len(group) - 1
   483→
   484→		// Estimate storage saved
   485→		for _, fingerprint := range group {
   486→			if fingerprint != canonical {
   487→				stats.StorageSaved += int64(len(patches[fingerprint]))
   488→			}
   489→		}
   490→	}
   491→
   492→	return stats, nil
   493→}
   494→
   495→// findSimilarPatches groups patches by similarity
   496→func (pd *PatchDeduplicator) findSimilarPatches(patches map[string][]byte) [][]string {
   497→	fingerprints := make([]string, 0, len(patches))
   498→	for fp := range patches {
   499→		fingerprints = append(fingerprints, fp)
   500→	}
   501→
   502→	var groups [][]string
   503→	processed := make(map[string]bool)
   504→
   505→	for _, fp1 := range fingerprints {
   506→		if processed[fp1] {
   507→			continue
   508→		}
   509→
   510→		group := []string{fp1}
   511→		processed[fp1] = true
   512→
   513→		// Find similar patches
   514→		for _, fp2 := range fingerprints {
   515→			if processed[fp2] || fp1 == fp2 {
   516→				continue
   517→			}
   518→
   519→			similarity := pd.sigGenerator.ComputePatchSimilarity(patches[fp1], patches[fp2])
   520→			if similarity >= pd.config.SimilarityThresholdForMerge {
   521→				group = append(group, fp2)
   522→				processed[fp2] = true
   523→			}
   524→		}
   525→
   526→		if len(group) > 1 {
   527→			groups = append(groups, group)
   528→		}
   529→	}
   530→
   531→	return groups
   532→}
